mapper.select:
SELECT CASE WHEN progress = 0 THEN '未开始' WHEN progress > 0 AND progress < 25 THEN '0-25%' WHEN progress >= 25 AND progress < 50 THEN '25-50%' WHEN progress >= 50 AND progress < 75 THEN '50-75%' WHEN progress >= 75 AND progress < 100 THEN '75-100%' WHEN progress = 100 THEN '已完成' END as progress_range, COUNT(*) as count FROM project_manage_wbs WHERE del_flag = '0'
AND project_id = #{projectId}
GROUP BY progress_range

SELECT CASE WHEN DATEDIFF(plan_end_time, CURDATE()) <= 3 AND progress < 100 THEN 1 WHEN DATEDIFF(plan_end_time, CURDATE()) <= 7 AND progress < 80 THEN 2 WHEN DATEDIFF(plan_end_time, CURDATE()) <= 14 AND progress < 60 THEN 3 ELSE 0 END as warning_level, COUNT(*) as count FROM project_manage_wbs WHERE del_flag = '0' AND status IN (0, 2)
AND project_id = #{projectId}
GROUP BY warning_level HAVING warning_level > 0

SELECT w.id as task_id, w.name as task_name, w.code as task_code, w.project_id, p.name as project_name, w.principal_id, u.user_name as principal_name, w.plan_start_time, w.plan_end_time, w.progress, w.status FROM project_manage_wbs w LEFT JOIN project_manage_info p ON w.project_id = p.id AND p.del_flag = '0' LEFT JOIN sys_user u ON w.principal_id = u.user_id AND u.del_flag = '0' WHERE w.del_flag = '0'
AND w.project_id = #{projectId}
ORDER BY w.update_time DESC LIMIT #{limit}

SELECT w.id as task_id, w.name as task_name, w.code as task_code, w.project_id, p.name as project_name, w.principal_id, u.user_name as principal_name, w.plan_start_time, w.plan_end_time, w.progress, w.status FROM project_manage_wbs w LEFT JOIN project_manage_info p ON w.project_id = p.id AND p.del_flag = '0' LEFT JOIN sys_user u ON w.principal_id = u.user_id AND u.del_flag = '0' WHERE w.del_flag = '0' AND w.status IN (1, 4, 6)
AND w.project_id = #{projectId}
ORDER BY w.plan_end_time ASC LIMIT #{limit}
